# BEST PRACTICE: Model Freezing with Version Control
from transformers import AutoTokenizer, AutoModelForSequenceClassification
import os

# Pre-download during setup, cache path is versioned
MODEL_NAME = "bert-base-uncased"
CACHE_DIR = "/models/v2.1/bert_base"
os.environ['TRANSFORMERS_CACHE'] = CACHE_DIR

# Freeze version in requirements.txt
# transformers==4.30.2
# torch==2.0.1+cu118

class CricketScorePredictor:
    def __init__(self):
        self.tokenizer = AutoTokenizer.from_pretrained(MODEL_NAME, cache_dir=CACHE_DIR)
        self.model = AutoModelForSequenceClassification.from_pretrained(MODEL_NAME, cache_dir=CACHE_DIR)
        self.model.eval()

    def predict_match_outcome(self, commentary):
        inputs = self.tokenizer(commentary, return_tensors="pt", truncation=True, max_length=512)
        with torch.no_grad():
            outputs = self.model(**inputs)
        return outputs.logits

# ANTI-PATTERN: Dynamic downloads without version pinning
class BadCricketPredictor:
    def __init__(self):
        # ❌ No cache directory, downloads fresh each time
        self.tokenizer = AutoTokenizer.from_pretrained("bert-base-uncased")
        # ❌ No version pinning, different versions between runs
        self.model = AutoModelForSequenceClassification.from_pretrained("bert-base-uncased")

    def predict_match_outcome(self, commentary):
        # ❌ Model not in eval mode, behavior inconsistent
        inputs = self.tokenizer(commentary, return_tensors="pt")
        outputs = self.model(**inputs)  # Non-deterministic with dropout
        return outputs.logits

# BEST PRACTICE: Lazy Loading for Memory Efficiency
class LazyBatsmanAnalyzer:
    _instance = None

    def __init__(self):
        self._model = None
        self._tokenizer = None

    @property
    def model(self):
        if self._model is None:
            self._model = AutoModelForSequenceClassification.from_pretrained("distilbert-base-uncased")
            self._model.eval()
        return self._model

    @property
    def tokenizer(self):
        if self._tokenizer is None:
            self._tokenizer = AutoTokenizer.from_pretrained("distilbert-base-uncased")
        return self._tokenizer

    @classmethod
    def get_instance(cls):
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

# ANTI-PATTERN: Reinitializing on every prediction
class BadBatsmanAnalyzer:
    def analyze_batting_style(self, stats):
        # ❌ Loads model EVERY time—huge overhead
        model = AutoModelForSequenceClassification.from_pretrained("distilbert-base-uncased")
        tokenizer = AutoTokenizer.from_pretrained("distilbert-base-uncased")
        inputs = tokenizer(stats, return_tensors="pt")
        return model(**inputs)
